const userRepo = require('../repositories/userRepository');
const bcrypt = require('bcrypt');

module.exports = {
  findAll() {
    return userRepo.findAll();
  },
  findById(id) {
    const user = userRepo.findById(id);
    if (!user) throw { status: 404, message: 'Felhasználó nem található.' };
    return user;
  },
  create(data) {
    if (!data.username || data.username.trim() === '') {
      throw { status: 400, message: 'A felhasználónév kötelező.' };
    }
    if (!data.email) {
      throw { status: 400, message: 'Az e-mail kötelező.' };
    }
    if (!data.password) {
      throw { status: 400, message: 'A jelszó kötelező.' };
    }
    // E-mail egyediség
    const existing = userRepo.findByEmail(data.email);
    if (existing) {
      throw { status: 409, message: 'Az e-mail már létezik.' };
    }
    // Hash the password before creating the user
    const hashed = bcrypt.hashSync(data.password, 10);
    const toCreate = { ...data, password: hashed };
    return userRepo.create(toCreate);
  },
  update(id, data) {
    if (data.username !== undefined && data.username.trim() === '') {
      throw { status: 400, message: 'A felhasználónév nem lehet üres.' };
    }
    // If updating password, hash it
    const updatedData = { ...data };
    if (updatedData.password) {
      updatedData.password = bcrypt.hashSync(updatedData.password, 10);
    }
    const updated = userRepo.update(id, updatedData);
    if (!updated) throw { status: 404, message: 'Felhasználó nem található.' };
    return updated;
  },
  delete(id) {
    const ok = userRepo.delete(id);
    if (!ok) throw { status: 404, message: 'Felhasználó nem található.' };
    return true;
  },
  findByEmail(email) {
    const user = userRepo.findByEmail(email);
    if (!user) throw { status: 404, message: 'Felhasználó nem található.' };
    return user;
  }
};

// Felhasználók in-memory repository
const bcrypt = require('bcrypt');

const users = [
  { id: '1', username: 'admin', email: 'admin@recept.hu', role: 'admin', password: bcrypt.hashSync('admin123', 10), createdAt: new Date().toISOString() },
  { id: '2', username: 'pista', email: 'pista@recept.hu', role: 'user', password: bcrypt.hashSync('pista123', 10), createdAt: new Date().toISOString() }
];

let nextId = 3;

module.exports = {
  findAll() {
    return users;
  },
  findById(id) {
    return users.find(u => u.id === id);
  },
  create(data) {
    const newUser = { id: String(nextId++), ...data, createdAt: new Date().toISOString() };
    users.push(newUser);
    return newUser;
  },
  update(id, data) {
    const idx = users.findIndex(u => u.id === id);
    if (idx === -1) return null;
    users[idx] = { ...users[idx], ...data };
    return users[idx];
  },
  delete(id) {
    const idx = users.findIndex(u => u.id === id);
    if (idx === -1) return false;
    users.splice(idx, 1);
    return true;
  },
  findByEmail(email) {
    return users.find(u => u.email === email);
  }
};

const userRepo = require('../repositories/userRepository');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');

const SECRET = process.env.JWT_SECRET || 'dev_jwt_secret';

module.exports = {
  login({ email, password }) {
    if (!email || !password) throw { status: 400, message: 'E-mail és jelszó kötelező.' };
    const user = userRepo.findByEmail(email);
    if (!user) throw { status: 401, message: 'Érvénytelen adatok.' };
    const ok = bcrypt.compareSync(password, user.password);
    if (!ok) throw { status: 401, message: 'Érvénytelen adatok.' };
    const payload = { id: user.id, username: user.username, role: user.role };
    const token = jwt.sign(payload, SECRET, { expiresIn: '7d' });
    return { token, user: payload };
  },
  verifyToken(token) {
    return jwt.verify(token, SECRET);
  }
};

const authService = require('../services/authService');

module.exports = (req, res, next) => {
  const auth = req.headers.authorization;
  if (!auth || !auth.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Hiányzó azonosító token.' });
  }
  const token = auth.substring(7);
  try {
    const payload = authService.verifyToken(token);
    req.user = payload;
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Érvénytelen vagy lejárt token.' });
  }
};

const express = require('express');
const router = express.Router();
const userService = require('../services/userService');
const authService = require('../services/authService');

router.post('/auth/register', (req, res) => {
  try {
    const newUser = userService.create(req.body);
    // After registration, return a token as well
    const result = authService.login({ email: newUser.email, password: req.body.password });
    res.status(201).json({ user: newUser, token: result.token });
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

router.post('/auth/login', (req, res) => {
  try {
    const result = authService.login(req.body);
    res.status(200).json(result);
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

module.exports = router;

